INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 82, 1, "柔和で、寛容で、お話のわかる……\n彼女こそ、真の保育士さんで\nいらっしゃいますね。", 0, 10, 0, 82029, 0, 1, 11);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, 82, 0, "", "", 0, "", 82030, "", "", 91);
